import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.pdforge.com/getting-started/authentication";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSaf";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from PDForge API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:pdforge",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const pdforgeFirewall = {",
    '  name: "pdforge",',
    '  description: "PDForge PDF Generation API",',
    "  placeholders: {",
    `    PDFORGE_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.pdforge.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.PDFORGE_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating PDForge firewall config...");
  const ts = generateTypeScript();
  writeOutput("pdforge", ts, import.meta.dirname);
}
